# -*- coding: utf-8 -*-
import re
import sys

try:
    from scapy.all import rdpcap, TCP, IP, Raw, HTTP
    from scapy.layers.http import HTTPRequest, HTTPResponse
except ImportError:
    print("正在尝试使用pyshark作为备选...")
    try:
        import pyshark
        USE_PYSHARK = True
    except ImportError:
        print("错误: 需要安装 scapy 或 pyshark")
        sys.exit(1)
    USE_PYSHARK = True
else:
    USE_PYSHARK = False

pcap_file = r"C:\Users\ASUS\Desktop\agent-test\agent-web\challenges\web_demo\workspace\0-2000.pcap"

print(f"正在分析流量包: {pcap_file}\n")

# 攻击特征列表
attack_patterns = {
    'SQL注入': [r'union\s+select', r'or\s+1\s*=\s*1', r'\'.*or.*\'', r'sleep\(', r'benchmark\(', r'information_schema'],
    'XSS攻击': [r'<script', r'javascript:', r'onerror=', r'onload=', r'alert\(', r'<img.*src'],
    '目录遍历': [r'\.\./', r'\.\.\\', r'etc/passwd', r'windows/system32'],
    '命令注入': [r';\s*cat\s+', r';\s*ls\s+', r'\|\s*whoami', r'`.*`', r'\$\(.*\)'],
    'XXE注入': [r'<!ENTITY', r'SYSTEM\s+"file:', r'<!DOCTYPE'],
    'SSTI': [r'\{\{.*\}\}', r'\{%.*%\}', r'\{\{.*config.*\}\}'],
}

# Flag模式
flag_patterns = [
    r'flag\{[^}]+\}',
    r'FLAG\{[^}]+\}',
    r'hgame\{[A-Za-z0-9_\-]+\}',
    r'ctf\{[^}]+\}',
    r'[a-f0-9]{32}',  # MD5
]

findings = []
flags_found = []

