    # 使用 Scapy
    try:
        packets = rdpcap(pcap_file)
        print(f"成功读取 {len(packets)} 个数据包\n")

        for i, pkt in enumerate(packets):
            if pkt.haslayer(Raw):
                payload = pkt[Raw].load
                try:
                    payload_str = payload.decode('utf-8', errors='ignore')
                except:
                    payload_str = str(payload)

                # 检查攻击特征
                for attack_type, patterns in attack_patterns.items():
                    for pattern in patterns:
                        if re.search(pattern, payload_str, re.IGNORECASE):
                            findings.append(f"[数据包 #{i}] 检测到 {attack_type}: {pattern}")
                            break

                # 检查Flag
                for flag_pattern in flag_patterns:
                    matches = re.findall(flag_pattern, payload_str, re.IGNORECASE)
                    if matches:
                        for match in matches:
                            if match not in flags_found:
                                flags_found.append(match)
                                findings.append(f"[数据包 #{i}] 发现可疑Flag: {match}")

                # 检查HTTP请求
                if b'HTTP' in payload or b'GET' in payload or b'POST' in payload:
                    if b'User-Agent' in payload:
                        findings.append(f"[数据包 #{i}] HTTP请求")

    except Exception as e:
        print(f"Scapy分析出错: {e}")
        print("尝试使用原始方法读取...")

# 如果Scapy失败，使用原始字节读取
if not findings:
    try:
        with open(pcap_file, 'rb') as f:
            content = f.read()
            content_str = content.decode('utf-8', errors='ignore')

            # 检查攻击特征
            for attack_type, patterns in attack_patterns.items():
                for pattern in patterns:
                    if re.search(pattern, content_str, re.IGNORECASE):
                        findings.append(f"检测到 {attack_type}: {pattern}")

            # 检查Flag
            for flag_pattern in flag_patterns:
                matches = re.findall(flag_pattern, content_str, re.IGNORECASE)
                if matches:
                    for match in matches:
                        if match not in flags_found:
                            flags_found.append(match)
                            findings.append(f"发现可疑Flag: {match}")
    except Exception as e:
        print(f"原始读取出错: {e}")

# 输出结果
print("=" * 60)
print("流量分析报告")
print("=" * 60)

if findings:
    print(f"\n检测到 {len(findings)} 个可疑活动:\n")
    for finding in findings[:50]:  # 限制输出前50条
        print(f"  • {finding}")
else:
    print("\n未检测到明显的攻击特征")

if flags_found:
    print(f"\n\n发现 {len(flags_found)} 个可能的Flag:")
    for flag in flags_found:
        print(f"  >>> {flag}")
else:
    print("\n未发现Flag")

print("\n" + "=" * 60)

# 生成结论文本
conclusion = f"""流量包分析结论
================

文件名: 0-2000.pcap
分析时间: 自动分析

一、总体评估
{'检测到攻击流量' if findings else '未检测到明显攻击流量'}

二、攻击类型统计
"""

